SELECT bs."in.comstock_building_type" AS comstock_building_type, ts_aggr.timestamp AS timestamp, count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS sample_count, (count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(ts_aggr._inner_rows) / CAST(count(DISTINCT (bs.bldg_id, bs."in.nhgis_tract_gisjoin", bs.state)) AS DECIMAL) AS rows_per_sample, sum(ts_aggr."bs__out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption", sum(ts_aggr."bs__out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption" FROM (SELECT ts_flat.bldg_id AS bldg_id, ts_flat.state AS state, ts_flat.timestamp AS timestamp, sum(ts_flat."_v__out.electricity.total.energy_consumption") AS "bs__out.electricity.total.energy_consumption", sum(ts_flat."_v__out.natural_gas.total.energy_consumption") AS "bs__out.natural_gas.total.energy_consumption", count(*) AS _inner_rows FROM (SELECT comstock_amy2018_r2_2025_ts_by_state.bldg_id AS bldg_id, comstock_amy2018_r2_2025_ts_by_state.state AS state, date_trunc('month', date_add('second', -900, comstock_amy2018_r2_2025_ts_by_state.timestamp)) AS timestamp, comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" AS "_v__out.electricity.total.energy_consumption", comstock_amy2018_r2_2025_ts_by_state."out.natural_gas.total.energy_consumption" AS "_v__out.natural_gas.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state WHERE comstock_amy2018_r2_2025_ts_by_state.upgrade IN (0) AND comstock_amy2018_r2_2025_ts_by_state.state IN ('CO', 'NM')) AS ts_flat GROUP BY ts_flat.bldg_id, ts_flat.state, ts_flat.timestamp) AS ts_aggr JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs ON bs.bldg_id = ts_aggr.bldg_id AND bs.state = ts_aggr.state AND bs.upgrade = 0 AND bs.state IN ('CO', 'NM') GROUP BY 1, 2 ORDER BY 1, 2